hooks.command:
python3 -c "
import json, os, sys
try:
    d = json.loads(os.environ.get('CLAUDE_TOOL_INPUT', '{}'))
    cmd = d.get('command', '')
except Exception:
    sys.exit(0)
if 'pytest tests/' in cmd or cmd.strip().startswith('pytest tests'):
    print('STOP: Do not run the full test suite. Target a specific test: uv run pytest tests/test_<name>.py::test_name -x -v')
    sys.exit(2)
if cmd.strip().startswith('cat src/'):
    print('STOP: Do not cat entire source files. Use targeted reads or sed -n line ranges.')
    sys.exit(2)
if any(pat in cmd for pat in ['grep -r', 'grep -rn', 'rg ', 'find . -name']):
    if os.path.exists('graphify-out/graph.json'):
        print('STOP: graphify graph exists. Run: graphify query \"<what you need>\" instead of grep. Use grep ONLY if graphify returns nothing.')
        sys.exit(2)
sys.exit(0)
"
